// nineteen-file-specials.js
//
// 1. Scans:
//    - All existing hotel‑data pages (*_file_specials output) in ./output
//    - All saving‑guidance pages generated by eighteen-file-specials.js
// 2. For each hotel page:
//    - Injects 1 contextual internal link to a related saving‑guidance page
// 3. For each saving page:
//    - Injects 1 contextual internal link back to a related hotel page
// 4. Result: every visitor can go:
//    - Hotel page → Saving page (and back) = 1 clean “save money” journey

const fs = require("fs-extra");
const path = require("path");

const OUTPUT_DIR = path.resolve("./output");

// 1 = hotel page, 2 = saving‑guidance page
const PAGE_TYPES = {
  HOTEL: 1,
  SAVING: 2,
};

const LEXICON = {
  "hotel": "hotel",
  "resort": "all-inclusive-resort",
  "beach": "beachfront",
  "spa": "spa",
  "family": "family",
  "pet-friendly": "pet-friendly",
  "apartment": "apart-hotel",
  "villa": "villa",
  "luxury": "luxury",
};

// ==============================
// 1. ANALYZE ALL PAGES (HOTEL + SAVING)
// ==============================

async function scanAllPages() {
  const pages = [];

  try {
    const allFiles = await fs.readdir(OUTPUT_DIR, { recursive: true });
    for (const file of allFiles) {
      const fullPath = path.join(OUTPUT_DIR, file);
      const stat = await fs.stat(fullPath);
      if (!stat.isFile()) continue;

      const ext = path.extname(file).toLowerCase();
      if (!ext.endsWith(".html")) continue;

      const content = await fs.readFile(fullPath, "utf8");

      let type = PAGE_TYPES.HOTEL;

      if (file.includes("save-")) {
        type = PAGE_TYPES.SAVING;
      }

      pages.push({
        file,
        absPath: fullPath,
        type,
        content,
      });
    }

    console.log(`nineteen-file-specials.js: loaded ${pages.length} pages (Hotel + Saving).`);
    return pages;
  } catch (err) {
    console.error("Error scanning pages:", err.message);
    return [];
  }
}

// ==============================
// 2. BUILD CITY + TYPE MAPPINGS FOR LINKING
// ==============================

function buildLinkMap(pages) {
  const byCity = new Map();
  const byType = new Map();

  pages.forEach((page) => {
    // Extract city
    let cityMatch;
    const cityRegex = /.*hotels?-(in-)([a-z0-9-]+)/;
    const sRegex = /save-([a-z0-9-]+)-/;
    const inHotels = page.file.match(cityRegex);
    const inSave = page.file.match(sRegex);

    if (inHotels && inHotels[2]) {
      cityMatch = inHotels[2].replace("-", " ");
    } else if (inSave && inSave[1] && inSave[1] !== "global") {
      cityMatch = inSave[1].replace("-", " ");
    }

    // Extract type
    let typeMatch;
    for (const [key, val] of Object.entries(LEXICON)) {
      if (page.file.includes(key)) {
        typeMatch = val;
        break;
      }
    }

    if (cityMatch) {
      const key = cityMatch + (typeMatch ? `-${typeMatch}` : "");
      if (!byCity.has(key)) byCity.set(key, []);
      byCity.get(key).push(page);
    }

    if (typeMatch) {
      if (!byType.has(typeMatch)) byType.set(typeMatch, []);
      byType.get(typeMatch).push(page);
    }
  });

  return { byCity, byType };
}

// ==============================
// 3. FIND A RELATED SAVING PAGE FOR A HOTEL
// ==============================

function findRelatedSavingPage(hotel, allSaving, byCity, byType) {
  // 1. City + type
  const cityKey = hotel.city || "";
  const typeKey = hotel.type || "";

  const highKey = `${cityKey}-${typeKey}`;
  if (byCity.has(highKey)) {
    const pool = byCity.get(highKey).filter((p) => p.type === PAGE_TYPES.SAVING);
    if (pool.length > 0) {
      return pool[Math.floor(Math.random() * pool.length)];
    }
  }

  // 2. Type only
  if (typeKey && byType.has(typeKey)) {
    const pool = byType.get(typeKey).filter((p) => p.type === PAGE_TYPES.SAVING);
    if (pool.length > 0) {
      return pool[Math.floor(Math.random() * pool.length)];
    }
  }

  // 3. Any global saving page
  const globals = allSaving.filter((p) => p.file.includes("save-") && !p.file.includes("global"));
  if (globals.length > 0) {
    return globals[Math.floor(Math.random() * globals.length)];
  }

  // 4. First saving ever
  const firstSaving = allSaving.find((p) => p.type === PAGE_TYPES.SAVING);
  return firstSaving || null;
}

// ==============================
// 4. INJECT SAVING LINK INTO HOTEL PAGE
// ==============================

function injectSavingLinkIntoHotel(hotel, saving, lang = "en") {
  const hotelCity = hotel.file.replace(/.*hotels?-in-([a-z0-9-]+).*/i, "$1").replace(/-/g, " ");
  const anchorText =
    lang === "en" ? `How to save money when staying in ${hotelCity}`
    : lang === "es" ? `Cómo ahorrar dinero alojándote en ${hotelCity}`
    : lang === "de" ? `Wie man Geld spart, wenn man in ${hotelCity} übernachtet`
    : `How to save money when staying in ${hotelCity}`;

  const linkHtml =
    `<p class="mt-4">\n  ` +
    `<a href="/${saving.file}" rel="noopener" class="text-decoration-none">` +
    `${anchorText}</a>\n  ` +
    `</p>`;

  const body = /<body[^>]*>([\s\S]*)<\/body>/i;
  if (body.test(hotel.content)) {
    return hotel.content.replace(
      body,
      (whole, bodyInner) => {
        return `<body>\n${bodyInner}${linkHtml}\n</body>`;
      }
    );
  }

  return hotel.content;
}

// ==============================
// 5. INJECT HOTEL LINK INTO SAVING PAGE
// ==============================

function injectHotelLinkIntoSaving(saving, hotel, lang = "en") {
  const hotelCity = hotel.file.replace(/.*hotels?-in-([a-z0-9-]+).*/i, "$1").replace(/-/g, " ");

  const anchorText =
    lang === "en" ? `Check hotels in ${hotelCity} on Booking.com`
    : lang === "es" ? `Revisa hoteles en ${hotelCity} en Booking.com`
    : lang === "de" ? `Hotels in ${hotelCity} bei Booking.com ansehen`
    : `Check hotels in ${hotelCity} on Booking.com`;

  const linkHtml =
    `<p class="mt-4">\n  ` +
    `<a href="/${hotel.file}" rel="noopener" class="text-decoration-none">` +
    `${anchorText}</a>\n  ` +
    `</p>`;

  const body = /<body[^>]*>([\s\S]*)<\/body>/i;
  if (body.test(saving.content)) {
    return saving.content.replace(
      body,
      (whole, bodyInner) => {
        return `<body>\n${bodyInner}${linkHtml}\n</body>`;
      }
    );
  }

  return saving.content;
}

// ==============================
// 6. PROCESS AND REWRITE PAGES
// ==============================

async function processPages(pages, linkMap) {
  const hotels = pages.filter((p) => p.type === PAGE_TYPES.HOTEL);
  const savings = pages.filter((p) => p.type === PAGE_TYPES.SAVING);

  let linkCount = 0;

  for (const hotel of hotels) {
    const lang = hotel.file.includes("/es/") ? "es" :
                 hotel.file.includes("/de/") ? "de" :
                 hotel.file.includes("/fr/") ? "fr" :
                 hotel.file.includes("/zh/") ? "zh" :
                 "en";

    const relatedSaving = findRelatedSavingPage(
      { city: hotel.file.match(/hotels?-in-([a-z0-9-]+)/)?.[1], type: "hotel" },
      savings,
      linkMap.byCity,
      linkMap.byType
    );

    if (relatedSaving) {
      let newContent = injectSavingLinkIntoHotel(hotel, relatedSaving, lang);
      await fs.writeFile(hotel.absPath, newContent);
      console.log(`✓ Added saving link to ${hotel.file} → ${relatedSaving.file}`);
      linkCount++;

      // 1 back‑link per saving page to a hotel
      const backContent = injectHotelLinkIntoSaving(relatedSaving, hotel, lang);
      await fs.writeFile(relatedSaving.absPath, backContent);
      console.log(`✓ Added hotel link to ${relatedSaving.file} → ${hotel.file}`);
    }
  }

  console.log(`✅ nineteen-file-specials.js: interlinked ${linkCount} hotel + saving journeys.`);
}

// ==============================
// 7. MAIN – nineteen-file-specials.js
// ==============================

async function generateNineteenFileSpecials() {
  const pages = await scanAllPages();
  if (pages.length === 0) {
    console.log("nineteen-file-specials.js: no pages to interlink; exiting.");
    return;
  }

  const linkMap = buildLinkMap(pages);
  await processPages(pages, linkMap);

  console.log("✅ nineteen-file-specials.js finished: every visitor now has a hotel → saving‑tip path (and back).");
}

generateNineteenFileSpecials().catch((err) => {
  console.error("nineteen-file-specials.js error:", err.message);
});
